#include<bits/stdc++.h>
using namespace std;
const int N=200010;
int n,m,t[N],dp[N],s1[N],s2[N],cnt[N];
int main()
{
	scanf("%d%d",&n,&m);
	for(int i=1;i<=n;i++)
	{
		scanf("%d",&t[i]);
		t[i]++;
	}
	sort(t+1,t+1+n);
	for(int i=1;i<=n;i++)
	{
		if(t[i]-t[i-1]>=2*m)
		{
			int temp=t[i]-t[i-1]-2*m;
			for(int j=i;j<=n;j++)
			{
				t[j]-=temp;
			}
		}
	}
	for(int i=1;i<=n;i++)
	{
		cnt[t[i]]++;
	}
	int T=t[n]+m;
	for(int i=1;i<=T;i++)
	{
		s1[i]=s1[i-1]+cnt[i];
		s2[i]=s2[i-1]+i*cnt[i];
	}
	int ans=1e9;
	for(int i=1;i<=T;i++)
	{
		dp[i]=s1[i]*i-s2[i];
		for(int j=i-m;j>=max(1,i-2*m+1);j--)
		{
			dp[i]=min(dp[i],dp[j]+i*(s1[i]-s1[j])-(s2[i]-s2[j]));
		}
		if(i>=t[n])
		{
			ans=min(ans,dp[i]);
		}
	}
	printf("%d",ans);
	return 0;
}
